#include <unistd.h>

typedef struct {
    int data;
    int readers;
    int read_count;
} RWData;

int main(void) {
    RWData *rw = (RWData *)mmap(NULL, sizeof(RWData),
        PROT_READ | PROT_WRITE, MAP_SHARED | MAP_ANONYMOUS, -1, 0);
    rw->data = 42;
    rw->readers = 0;
    rw->read_count = 0;

    sem_t *mutex    = sem_open("/kf_sem_rmtx", O_CREAT | O_EXCL, 0644, 1);
    sem_t *rw_mutex = sem_open("/kf_sem_rwm",  O_CREAT | O_EXCL, 0644, 1);

    for (int i = 0; i < 2; i++) {
        pid_t pid = fork();
        if (pid == 0) {
            sem_wait(mutex);
            rw->readers++;
            if (rw->readers == 1)
                ____(rw_mutex);
            sem_post(mutex);

            rw->read_count++;

            sem_wait(mutex);
            rw->readers--;
            if (rw->readers == 0)
                ____(rw_mutex);
            sem_post(mutex);
            _exit(0);
        }
        waitpid(pid, NULL, 0);
    }

    pid_t wpid = fork();
    if (wpid == 0) {
        sem_wait(rw_mutex);
        rw->data = 99;
        sem_post(rw_mutex);
        _exit(0);
    }
    waitpid(wpid, NULL, 0);

    printf("Reads: %d\n", rw->read_count);
    printf("Data: %d\n", rw->data);

    sem_close(mutex); sem_close(rw_mutex);
    sem_unlink("/kf_sem_rmtx");
    sem_unlink("/kf_sem_rwm");
    munmap(rw, sizeof(RWData));
    return 0;
}

